/**
 * TaskManager — Smoke Test
 * Generated by: formal-agent-contracts plugin v1.0.0 (integrated-workflow)
 *
 * Tests:
 * 1. Task creation with valid/invalid inputs
 * 2. Status transitions (valid and invalid)
 * 3. Task update preserving status
 * 4. Task deletion
 * 5. Board summary
 * 6. Filter and query functions
 * 7. Invariant enforcement
 */

// Inline the module (for single-file execution)
const CONTRACT_CHECK = true;

class ContractError extends Error {
  constructor(message: string) {
    super(`[Contract Violation] ${message}`);
    this.name = "ContractError";
  }
}

function checkPre(condition: boolean, message: string): void {
  if (CONTRACT_CHECK && !condition) throw new ContractError(`Pre-condition failed: ${message}`);
}
function checkPost(condition: boolean, message: string): void {
  if (CONTRACT_CHECK && !condition) throw new ContractError(`Post-condition failed: ${message}`);
}
function checkInv(condition: boolean, message: string): void {
  if (CONTRACT_CHECK && !condition) throw new ContractError(`Invariant violated: ${message}`);
}

type TaskId = number;
type Priority = "Low" | "Medium" | "High";
type Status = "Todo" | "InProgress" | "Done";

interface Task {
  readonly id: TaskId;
  readonly title: string;
  readonly desc: string;
  readonly status: Status;
  readonly priority: Priority;
  readonly assignee: string | null;
}

function invTask(t: Task): boolean {
  return t.title.length > 0 && t.title.length <= 100 && t.desc.length <= 500;
}

function mkTask(id: TaskId, title: string, desc: string, status: Status, priority: Priority, assignee: string | null): Task {
  checkPre(id >= 1, `TaskId must be nat1, got ${id}`);
  checkPre(title.length > 0, `title must be seq1 of char (non-empty)`);
  const task: Task = { id, title, desc, status, priority, assignee };
  checkInv(invTask(task), `Task invariant: title.len<=100, desc.len<=500`);
  return task;
}

type TaskBoard = Map<TaskId, Task>;

function invTaskBoard(board: TaskBoard): boolean {
  for (const [id, task] of board) {
    if (task.id !== id) return false;
  }
  return true;
}

function validTransition(fromSt: Status, toSt: Status): boolean {
  if (fromSt === toSt) return true;
  if (fromSt === "Done") return false;
  return true;
}

function countByStatus(board: TaskBoard, s: Status): number {
  let count = 0;
  for (const [, task] of board) { if (task.status === s) count++; }
  return count;
}

function filterByStatus(board: TaskBoard, s: Status): Set<Task> {
  const result = new Set<Task>();
  for (const [, task] of board) { if (task.status === s) result.add(task); }
  return result;
}

function getAssignedTasks(board: TaskBoard, person: string): Set<Task> {
  const result = new Set<Task>();
  for (const [, task] of board) { if (task.assignee === person) result.add(task); }
  return result;
}

class TaskManagerState {
  board: TaskBoard;
  nextId: TaskId;

  constructor() {
    this.board = new Map();
    this.nextId = 1;
  }

  private checkStateInvariant(): void {
    checkInv(this.nextId >= 1, `State invariant: nextId >= 1`);
    for (const id of this.board.keys()) {
      checkInv(id < this.nextId, `State invariant: id ${id} < nextId ${this.nextId}`);
    }
    checkInv(invTaskBoard(this.board), `State invariant: TaskBoard invariant`);
  }

  createTask(title: string, desc: string, priority: Priority, assignee: string | null): TaskId {
    checkPre(title.length > 0, `title must be non-empty`);
    checkPre(title.length <= 100, `title length <= 100, got ${title.length}`);
    checkPre(desc.length <= 500, `desc length <= 500, got ${desc.length}`);
    const oldNextId = this.nextId;
    const newId = this.nextId;
    const newTask = mkTask(newId, title, desc, "Todo", priority, assignee);
    this.board.set(newId, newTask);
    this.nextId++;
    checkPost(newId === oldNextId, `RESULT = old nextId`);
    checkPost(this.board.has(newId), `RESULT in dom board`);
    checkPost(this.board.get(newId)!.status === "Todo", `status = Todo`);
    this.checkStateInvariant();
    return newId;
  }

  changeStatus(taskId: TaskId, newStatus: Status): void {
    checkPre(this.board.has(taskId), `taskId ${taskId} not in dom board`);
    const oldTask = this.board.get(taskId)!;
    checkPre(validTransition(oldTask.status, newStatus), `Invalid transition: ${oldTask.status} → ${newStatus}`);
    const oldTitle = oldTask.title;
    const updated = mkTask(oldTask.id, oldTask.title, oldTask.desc, newStatus, oldTask.priority, oldTask.assignee);
    this.board.set(taskId, updated);
    checkPost(this.board.get(taskId)!.status === newStatus, `status = ${newStatus}`);
    checkPost(this.board.get(taskId)!.title === oldTitle, `title preserved`);
    this.checkStateInvariant();
  }

  updateTask(taskId: TaskId, title: string, desc: string, priority: Priority, assignee: string | null): void {
    checkPre(this.board.has(taskId), `taskId ${taskId} not in dom board`);
    checkPre(title.length > 0, `title must be non-empty`);
    checkPre(title.length <= 100, `title length <= 100`);
    checkPre(desc.length <= 500, `desc length <= 500`);
    const oldTask = this.board.get(taskId)!;
    const oldStatus = oldTask.status;
    const updated = mkTask(oldTask.id, title, desc, oldTask.status, priority, assignee);
    this.board.set(taskId, updated);
    checkPost(this.board.get(taskId)!.title === title, `title updated`);
    checkPost(this.board.get(taskId)!.status === oldStatus, `status preserved`);
    this.checkStateInvariant();
  }

  deleteTask(taskId: TaskId): void {
    checkPre(this.board.has(taskId), `taskId ${taskId} not in dom board`);
    const oldSize = this.board.size;
    this.board.delete(taskId);
    checkPost(!this.board.has(taskId), `taskId removed from board`);
    checkPost(this.board.size === oldSize - 1, `board size decreased by 1`);
    this.checkStateInvariant();
  }

  getSummary(): [number, number, number] {
    const t = countByStatus(this.board, "Todo");
    const i = countByStatus(this.board, "InProgress");
    const d = countByStatus(this.board, "Done");
    checkPost(t + i + d === this.board.size, `summary = board size`);
    return [t, i, d];
  }
}

// ============================================================
// Smoke Tests
// ============================================================

let passed = 0;
let failed = 0;

function expectOk(label: string, fn: () => void): void {
  try {
    fn();
    console.log(`✓ ${label}`);
    passed++;
  } catch (e: any) {
    console.log(`✗ ${label}: ${e.message}`);
    failed++;
  }
}

function expectThrow(label: string, fn: () => void): void {
  try {
    fn();
    console.log(`✗ ${label}: expected ContractError but succeeded`);
    failed++;
  } catch (e: any) {
    if (e instanceof ContractError) {
      console.log(`✓ ${label}: caught "${e.message}"`);
      passed++;
    } else {
      console.log(`✗ ${label}: unexpected error: ${e.message}`);
      failed++;
    }
  }
}

console.log("=== TaskManager: Integrated Workflow Smoke Test ===\n");

const mgr = new TaskManagerState();

// --- 1. Task Creation ---
console.log("--- 1. Task Creation ---");
let id1: TaskId = 0;
expectOk("CreateTask: 'Design API' (High, Alice)", () => {
  id1 = mgr.createTask("Design API", "Design the REST API endpoints", "High", "Alice");
});

let id2: TaskId = 0;
expectOk("CreateTask: 'Write Tests' (Medium, Bob)", () => {
  id2 = mgr.createTask("Write Tests", "Unit and integration tests", "Medium", "Bob");
});

let id3: TaskId = 0;
expectOk("CreateTask: 'Setup CI' (Low, null)", () => {
  id3 = mgr.createTask("Setup CI", "", "Low", null);
});

// Invalid: empty title
expectThrow("CreateTask: empty title rejected", () => {
  mgr.createTask("", "desc", "Low", null);
});

// Invalid: title too long
expectThrow("CreateTask: title > 100 chars rejected", () => {
  mgr.createTask("x".repeat(101), "desc", "Low", null);
});

// Invalid: desc too long
expectThrow("CreateTask: desc > 500 chars rejected", () => {
  mgr.createTask("Valid Title", "x".repeat(501), "Low", null);
});

// --- 2. Status Transitions ---
console.log("\n--- 2. Status Transitions ---");
expectOk("ChangeStatus: Todo → InProgress (id1)", () => {
  mgr.changeStatus(id1, "InProgress");
});

expectOk("ChangeStatus: InProgress → Done (id1)", () => {
  mgr.changeStatus(id1, "Done");
});

// Invalid: Done → InProgress
expectThrow("ChangeStatus: Done → InProgress rejected", () => {
  mgr.changeStatus(id1, "InProgress");
});

// Invalid: Done → Todo
expectThrow("ChangeStatus: Done → Todo rejected", () => {
  mgr.changeStatus(id1, "Todo");
});

// Valid: same status (no-op)
expectOk("ChangeStatus: Todo → Todo (no-op, id2)", () => {
  mgr.changeStatus(id2, "Todo");
});

// Valid: Todo → Done (skip InProgress)
expectOk("ChangeStatus: Todo → Done (id3)", () => {
  mgr.changeStatus(id3, "Done");
});

// Invalid: non-existent task
expectThrow("ChangeStatus: non-existent taskId rejected", () => {
  mgr.changeStatus(999, "Todo");
});

// --- 3. Update Task ---
console.log("\n--- 3. Update Task ---");
expectOk("UpdateTask: change title & priority (id2)", () => {
  mgr.updateTask(id2, "Write Integration Tests", "Full test suite", "High", "Bob");
});

// Verify status preserved after update
expectOk("UpdateTask: status preserved after update", () => {
  const task = mgr.board.get(id2)!;
  if (task.status !== "Todo") throw new Error(`Expected Todo, got ${task.status}`);
  if (task.title !== "Write Integration Tests") throw new Error(`Title not updated`);
});

// Invalid: update non-existent task
expectThrow("UpdateTask: non-existent taskId rejected", () => {
  mgr.updateTask(999, "Title", "", "Low", null);
});

// --- 4. Delete Task ---
console.log("\n--- 4. Delete Task ---");
const sizeBeforeDelete = mgr.board.size;
expectOk(`DeleteTask: id3 (board size ${sizeBeforeDelete} → ${sizeBeforeDelete - 1})`, () => {
  mgr.deleteTask(id3);
});

// Invalid: delete already deleted task
expectThrow("DeleteTask: already deleted taskId rejected", () => {
  mgr.deleteTask(id3);
});

// --- 5. Summary ---
console.log("\n--- 5. Board Summary ---");
expectOk("GetSummary: counts match board size", () => {
  const [todo, inProgress, done] = mgr.getSummary();
  console.log(`  Summary: Todo=${todo}, InProgress=${inProgress}, Done=${done}, Total=${mgr.board.size}`);
  if (todo + inProgress + done !== mgr.board.size) throw new Error("Summary mismatch");
});

// --- 6. Filter & Query Functions ---
console.log("\n--- 6. Filter & Query ---");
expectOk("FilterByStatus: Todo tasks", () => {
  const todos = filterByStatus(mgr.board, "Todo");
  console.log(`  Todo tasks: ${todos.size}`);
});

expectOk("GetAssignedTasks: Bob's tasks", () => {
  const bobTasks = getAssignedTasks(mgr.board, "Bob");
  console.log(`  Bob's tasks: ${bobTasks.size}`);
  if (bobTasks.size !== 1) throw new Error(`Expected 1, got ${bobTasks.size}`);
});

// --- 7. Invariant: Task record ---
console.log("\n--- 7. Invariant Enforcement ---");
expectThrow("mkTask: TaskId=0 (must be nat1) rejected", () => {
  mkTask(0, "Test", "", "Todo", "Low", null);
});

expectThrow("mkTask: empty title (seq1 of char) rejected", () => {
  mkTask(1, "", "", "Todo", "Low", null);
});

// --- Results ---
console.log(`\n=== Results: ${passed} passed, ${failed} failed ===`);
if (failed > 0) {
  process.exit(1);
}
